import { useState } from "react";

import { toast } from "react-toastify";

import MainBtns from "../Components/Buttons/MainBtns";
import InputForm from "../Components/Input/InputForm";
import AdditionalInformation from "../Components/TextComponents/AdditionalInformation";
import TitleText from "../Components/TextComponents/TitleText";

import config from "../config.json"
import axios from "axios";


function LoginPage() {
  const [email,setEmail] = useState();
  const [password, setPass] = useState();

  const Request = () =>{
    try{ 
    axios.post(config.BaseURL +"/auth/login", {
      email,
      password
    },{withCredentials: true})
  }
  catch(err){
    if (err.response?.status === 500){
      toast.error("Ошибка сервера");
    }
  }
  }


  return (
    <>
      <TitleText TextOnTitle={"Выполните вход чтобы продолжить"} MarginOnBot={"200px"}/>
      <InputForm TextPlaceholder="Адрес электронной почты" funct={setEmail}/>
      <InputForm TextPlaceholder={"Пароль"} funct={setPass}/>
      <MainBtns Style={"purple-btn"} Text={"Продолжить"} Width={"400px"} Height={68} FontSize={"30px"} FontWeight={"100"} Padding={0} MarginTop={"auto"} Funct={Request} />
      <AdditionalInformation FirstText={"Не зарегистрированы?"} SecondText={"Регистрирация"} NavigateTo={"/join/register"}/>
    </>
  );
}

export default LoginPage;
